"""Stiffened panel buckling result dataclasses."""

from dataclasses import dataclass


@dataclass
class PlateTypeBehaviourResults:
    """
    Stores results for the plate-type buckling behaviour of a stiffened panel.
    Based on BS EN 1993-1-5:2006, Section 4.5.2.

    args:
        sigma_crp: elastic critical plate buckling stress (MPa)
        Ac: gross area of the compression zone (except parts supported by adjacent plate) (mm2)
        beta_Ac: area reduction factor (Ac,eff,loc / Ac) (Eq. 4.7)
        lambda_p: relative plate slenderness of the equivalent plate (Eq. 4.7)
        rho: reduction factor for plate buckling (Section 4.4(2) using lambda_p in Eq. 4.7)
    """

    # Elastic critical plate buckling stress (Annex A.1)
    sigma_crp: float

    # Gross area of the compression zone (except parts supported by adjacent plate)
    Ac: float

    # Area reduction factor (Ac,eff,loc / Ac) (Eq. 4.7)
    beta_Ac: float

    # Relative plate slenderness of the equivalent plate (Eq. 4.7)
    lambda_p: float

    # Reduction factor for plate buckling (Section 4.4(2) using lambda_p in Eq. 4.7)
    rho: float

    def summary(self):
        """Returns a formatted string with the plate-type buckling status."""
        return (
            f"--- Plate Type Buckling Results ---\n"
            f"Elastic Critical Plate Buckling Stress (sigma_crp): {self.sigma_crp:.2f} MPa\n"
            f"Gross Area of the Compression Zone (Ac): {self.Ac:.2f} mm2\n"
            f"Area Reduction Factor (beta_Ac): {self.beta_Ac:.2f}\n"
            f"Relative Plate Slenderness (lambda_p): {self.lambda_p:.2f}\n"
            f"Reduction Factor for Plate Buckling (rho): {self.rho:.2f}"
        )


@dataclass
class ColumnTypeBehaviourResults:
    """
    Stores results for the column-type buckling behaviour of a stiffened panel.
    Based on BS EN 1993-1-5:2006, Section 4.5.3.
    """

    # Elastic critical column buckling stress (Eq. 4.8 or 4.9)
    sigma_crc: float

    # Gross second moment of area of the stiffener and adjacent plate parts
    Isl1: float

    # Gross area of the column (stiffener and adjacent plate parts) (Section 4.5.3(3))
    Asl1: float

    # Effective cross-sectional area of the Asl1 (Section 4.5.3(4))
    Asl_1_eff: float

    # Area reduction factor for the column (Asl,1,eff / Asl,1) (Eq. 4.11)
    beta_Ac: float

    # Relative column slenderness (Eq. 4.10 or 4.11)
    lambda_c: float

    # Radius of gyration of the column (Eq. 4.12)
    i: float

    # Maximum distance between C.G of plate, stiffenr, neutral axis of the effective column (Section 4.5.3(5))
    e: float

    # Imperfection factor for the relevant buckling curve (Eq. 4.12)
    alpha: float

    # Effective imperfection factor for chi_C (Eq. 4.12)
    alapha_e: float

    # Reduction factor for column buckling obtained from 6.3.1.2 EN 1993-1-1
    chi_c: float

    def summary(self):
        """Returns a formatted string with the column-type buckling status."""
        if self.Asl_1_eff <= 0:
            return ""
        summary = "--- Column Type Buckling Results ---\n"
        summary += f"Elastic Critical Column Buckling Stress (sigma_crc): {self.sigma_crc:.2f} MPa\n"
        summary += f"Gross Second Moment of Area of the Stiffener and Adjacent Plate Parts (Isl1): {self.Isl1:.2f} mm4\n"
        summary += f"Gross Area of the Column (Asl1): {self.Asl1:.2f} mm2\n"
        summary += f"Effective Cross-Sectional Area of the Asl1 (Asl_1_eff): {self.Asl_1_eff:.2f} mm2\n"
        summary += f"Area Reduction Factor for the Column (beta_Ac): {self.beta_Ac:.2f}\n"
        summary += f"Relative Column Slenderness (lambda_c): {self.lambda_c:.2f}\n"
        summary += f"Radius of Gyration of the Column (i): {self.i:.2f} mm\n"
        summary += f"Maximum Distance Between C.G of Plate, Stiffenr, Neutral Axis of the Effective Column (e): {self.e:.2f} mm\n"
        summary += f"Imperfection Factor for the Relevant Buckling Curve (alpha): {self.alpha:.2f}\n"
        summary += f"Effective Imperfection Factor for chi_C (alapha_e): {self.alapha_e:.2f}\n"
        summary += f"Reduction Factor for Column Buckling (chi_c): {self.chi_c:.2f}"
        return summary


@dataclass
class StiffenedPanelBucklingResults:
    """
    Stores results for the stiffened panel buckling analysis.
    Based on EN 1993-1-5:2006, Section 4.5.
    """

    # Results for the plate-type buckling behaviour of the panel
    plate_type_results: PlateTypeBehaviourResults

    # Results for the column-type buckling behaviour of the panel
    column_type_results: ColumnTypeBehaviourResults

    # final reduction factor column-plate interaction
    rho_c: float

    epsilon: float

    def summary(self):
        """Returns a formatted string with the buckling status."""
        return (
            f"--- Stiffened Panel Buckling Results ---\n"
            f"Plate Type Results: {self.plate_type_results.summary()}\n"
            f"Column Type Results: {self.column_type_results.summary()}\n"
            f"Final Reduction Factor Column-Plate Interaction (rho_c): {self.rho_c:.2f}\n"
        )
